#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

#include "../util/cuda_helper/cuda_helper.h"

extern "C" {

__global__ void kernel_cpu_cuda(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    int bid = blockIdx.x * blockDim.x + threadIdx.x;

    if (bid >= count) return;

    int threadsPerBlock = order < 1024 ? order : 1024;

    for (int i = 0; i < maxheight; i++) {
        for (int thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[currKnode[bid]].keys[thid] <= keys[bid]) && 
                (knodes[currKnode[bid]].keys[thid+1] > keys[bid])) {
                if (knodes[currKnode[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[currKnode[bid]].indices[thid];
                }
            }
        }
        currKnode[bid] = offset[bid];
    }

    for (int thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

void kernel_cpu(
    int cores_arg,
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = (count + threadsPerBlock - 1) / threadsPerBlock;

    time1 = get_time();

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, knodes_elem * sizeof(record));
    cudaMalloc(&d_knodes, knodes_elem * sizeof(knode));
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_records, records, knodes_elem * sizeof(record), cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_elem * sizeof(knode), cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    kernel_cpu_cuda<<<blocksPerGrid, threadsPerBlock>>>(
        d_records,
        d_knodes,
        knodes_elem,
        order,
        maxheight,
        count,
        d_currKnode,
        d_offset,
        d_keys,
        d_ans);

    cudaMemcpy(ans, d_ans, count * sizeof(record), cudaMemcpyDeviceToHost);

    cudaFree(d_records);
    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_ans);

    time2 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");

    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", 
           (float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time2-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", 
           (float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time2-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float) (time2-time0) / 1000000);
}

}

