#include <cuda.h>
#include <stdlib.h>
#include <stdio.h>

#include "../common.h"

#include "../util/timer/timer.h"

#include "../util/cuda_util.h"

__global__ void kernel_cuda(
    record *records,
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans,
    int threadsPerBlock)
{
    int bid = blockIdx.x * blockDim.x + threadIdx.x;

    if (bid >= count) return;

    int thid;
    int i;

    for (i = 0; i < maxheight; i++) {
        for (thid = 0; thid < threadsPerBlock; thid++) {
            if ((knodes[currKnode[bid]].keys[thid]) <= keys[bid] && 
                (knodes[currKnode[bid]].keys[thid+1] > keys[bid])) {
                if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }
        currKnode[bid] = offset[bid];
    }

    for (thid = 0; thid < threadsPerBlock; thid++) {
        if (knodes[currKnode[bid]].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

void 
kernel_gpu_cuda_wrapper(
    record *records,
    long records_mem,
    knode *knodes,
    long knodes_elem,
    long knodes_mem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    record *ans)
{
    long long time0;
    long long time1;
    long long time2;

    time0 = get_time();

    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int numBlocks = (count + threadsPerBlock - 1) / threadsPerBlock;

    record *d_records;
    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    record *d_ans;

    cudaMalloc(&d_records, records_mem);
    cudaMalloc(&d_knodes, knodes_mem);
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_ans, count * sizeof(record));

    cudaMemcpy(d_records, records, records_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
