#include <stdio.h>
#include <stdlib.h>
#include <cuda.h>

#include "./common.h"

__global__ void kernel_cuda_helper(
    knode *knodes,
    long knodes_elem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    int *results)
{
    int bid = blockIdx.x;
    int thid = threadIdx.x;
    int threadsPerBlock = blockDim.x;

    if (bid >= count) return;

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[currKnode[bid]].keys[thid]) <= keys[bid] && 
                (knodes[currKnode[bid]].keys[thid+1] > keys[bid])) {
                if (knodes[offset[bid]].indices[thid] < knodes_elem) {
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }
        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }
    }

    if (thid == 0) {
        results[bid] = knodes[currKnode[bid]].keys[0];
    }
}

void run_cuda_helper(
    knode *knodes,
    long knodes_elem,
    long knodes_mem,
    int order,
    long maxheight,
    int count,
    long *currKnode,
    long *offset,
    int *keys,
    int *results)
{
    setdevice();

    int threadsPerBlock = order < 1024 ? order : 1024;
    int blocksPerGrid = count;

    knode *d_knodes;
    long *d_currKnode;
    long *d_offset;
    int *d_keys;
    int *d_results;

    cudaMalloc(&d_knodes, knodes_mem);
    cudaMalloc(&d_currKnode, count * sizeof(long));
    cudaMalloc(&d_offset, count * sizeof(long));
    cudaMalloc(&d_keys, count * sizeof(int));
    cudaMalloc(&d_results, count * sizeof(int));

    cudaMemcpy(d_knodes, knodes, knodes_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_currKnode, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_offset, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(d_keys, keys, count * sizeof(int), cudaMemcpyHostToDevice);

    kernel_cuda_helper<<<blocksPerGrid, threadsPerBlock>>>(
        d_knodes, knodes_elem, order, maxheight, count,
        d_currKnode, d_offset, d_keys, d_results);

    checkCUDAError("kernel_cuda_helper launch");

    cudaMemcpy(results, d_results, count * sizeof(int), cudaMemcpyDeviceToHost);

    cudaFree(d_knodes);
    cudaFree(d_currKnode);
    cudaFree(d_offset);
    cudaFree(d_keys);
    cudaFree(d_results);
}

