__global__ void bpnn_layerforward_kernel(float *l1, float *l2, float **conn, int n1, int n2)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;

  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {	
      sum += conn[k][j] * l1[k]; 
    }
    l2[j] = squash_device(sum);
  }
}


void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  float sum;
  int j, k;

  l1[0] = 1.0f;

  int threads_per_block = 256;
  int num_blocks = (n2 + threads_per_block - 1) / threads_per_block;

  bpnn_layerforward_kernel<<<num_blocks, threads_per_block>>>(l1, l2, conn, n1, n2);

  for (j = 1; j <= n2; j++) {
    if (l2[j] == 0.0f) {
      sum = 0.0f;
      for (k = 0; k <= n1; k++) {	
        sum += conn[k][j] * l1[k]; 
      }
      l2[j] = squash(sum);
    }
  }
}


void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)  
{
  int j;
  float o, t, errsum;
  errsum = 0.0f;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}


__global__ void bpnn_hidden_error_kernel(float *delta_h, float *delta_o, float *hidden, float **who, int nh, int no)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;

  if (j <= nh) {
    float h = hidden[j];
    float sum = 0.0f;
    for (int k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
  }
}


void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err)
{
  int j, k;
  float h, sum, errsum;

  errsum = 0.0f;

  int threads_per_block = 256;
  int num_blocks = (nh + threads_per_block - 1) / threads_per_block;

  bpnn_hidden_error_kernel<<<num_blocks, threads_per_block>>>(delta_h, delta_o, hidden, who, nh, no);

  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}


__global__ void bpnn_adjust_weights_kernel(float *delta, float *ly, float **w, float **oldw, int ndelta, int nly)
{
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;

  if (j <= ndelta) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
