void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  float new_dw;
  int k, j;
  ly[0] = 1.0f;

  int threads_per_block = 256;
  int num_blocks = (ndelta + threads_per_block - 1) / threads_per_block;

  bpnn_adjust_weights_kernel<<<num_blocks, threads_per_block>>>(delta, ly, w, oldw, ndelta, nly);

  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
