void bpnn_layerforward_cuda(float *l1, float *l2, float **conn, int n1, int n2)
{
  float *d_l1, *d_l2, *d_conn;
  int conn_cols = n2 + 1;
  size_t l1_size = (n1 + 1) * sizeof(float);
  size_t l2_size = (n2 + 1) * sizeof(float);
  size_t conn_size = (n1 + 1) * (n2 + 1) * sizeof(float);

  cudaMalloc(&d_l1, l1_size);
  cudaMalloc(&d_l2, l2_size);
  cudaMalloc(&d_conn, conn_size);

  cudaMemcpy(d_l1, l1, l1_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_l2, l2, l2_size, cudaMemcpyHostToDevice);

  float *conn_flat = (float *)malloc(conn_size);
  for (int i = 0; i <= n1; i++) {
    for (int j = 0; j <= n2; j++) {
      conn_flat[i * conn_cols + j] = conn[i][j];
    }
  }
  cudaMemcpy(d_conn, conn_flat, conn_size, cudaMemcpyHostToDevice);

  d_l1[0] = 1.0;
  cudaMemcpy(d_l1, l1, l1_size, cudaMemcpyHostToDevice);

  int threads = THREADS;
  int blocks = (n2 + threads - 1) / threads;
  layerforward_cuda_kernel<<<blocks, threads>>>(d_l1, d_l2, d_conn, n1, n2, conn_cols);
  cudaDeviceSynchronize();

  cudaMemcpy(l2, d_l2, l2_size, cudaMemcpyDeviceToHost);

