		sum = 0;
		for(position = pos_ori; position < pos_ori+public.in2_sub_elem; position = position + public.in2_sub_rows){
			private_data.d_in2_sub[position] = private_data.d_in2_sub[position] + sum;
			sum = private_data.d_in2_sub[position];
		}

	}

	for(col=0; col<public.conv_cols; col++){
		for(row=0; row<public.conv_rows; row++){

		ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
		ori_col = col + public.in2_sub_cumh_sel_collow - 1;
		temp = private_data.d_in2_sub[ori_col*public.in2_sub_rows+ori_row];

		ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
		ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
		temp2 = private_data.d_in2_sub[ori_col*public.in2_sub_rows+ori_row];

		temp2 = temp - temp2;

		temp2 = temp2 - (private_data.d_in2_sub2_sqr[col*public.conv_rows+row] / public.in_mod_elem);

		if(temp2 < 0){
			temp2 = 0;
		}
		temp2 = sqrt(temp2);

		temp2 = denomT * temp2;

		private_data.d_conv[col*public.conv_rows+row] = private_data.d_conv[col*public.conv_rows+row] / temp2;

		}
	}

	cent = public.sSize + public.tSize + 1;
	pointer = public.frame_no-1+private_data.point_no*public.frames;
	tMask_row = cent + private_data.d_tRowLoc[pointer] - private_data.d_Row[private_data.point_no] - 1;
	tMask_col = cent + private_data.d_tColLoc[pointer] - private_data.d_Col[private_data.point_no] - 1;

	for(ei_new = 0; ei_new < public.tMask_elem; ei_new++){
		private_data.d_tMask[ei_new] = 0;
	}
	private_data.d_tMask[tMask_col*public.tMask_rows + tMask_row] = 1;

	for(col=1; col<=public.mask_conv_cols; col++){

		j = col + public.mask_conv_joffset;
		jp1 = j + 1;
		if(public.mask_cols < jp1){
			ja1 = jp1 - public.mask_cols;
		}
		else{
			ja1 = 1;
		}
		if(public.tMask_cols < j){
			ja2 = public.tMask_cols;
		}
		else{
			ja2 = j;
		}

		for(row=1; row<=public.mask_conv_rows; row++){

			i = row + public.mask_conv_ioffset;
			ip1 = i + 1;

			if(public.mask_rows < ip1){
				ia1 = ip1 - public.mask_rows;
			}
			else{
				ia1 = 1;
			}
			if(public.tMask_rows < i){
				ia2 = public.tMask_rows;
			}
			else{
				ia2 = i;
			}

			s = 0;

			for(ja=ja1; ja<=ja2; ja++){
				jb = jp1 - ja;
				for(ia=ia1; ia<=ia2; ia++){
					ib = ip1 - ia;
					s = s + private_data.d_tMask[public.tMask_rows*(ja-1)+ia-1] * 1;
				}
			}

			private_data.d_mask_conv[(col-1)*public.conv_rows+(row-1)] = private_data.d_conv[(col-1)*public.conv_rows+(row-1)] * s;

		}

	}

	fin_max_val = 0;
	fin_max_coo = 0;
	for(i=0; i<public.mask_conv_elem; i++){
		if(private_data.d_mask_conv[i]>fin_max_val){
			fin_max_val = private_data.d_mask_conv[i];
			fin_max_coo = i;
		}
	}

	largest_row = (fin_max_coo+1) % public.mask_conv_rows - 1;											
	largest_col = (fin_max_coo+1) / public.mask_conv_rows;												
	if((fin_max_coo+1) % public.mask_conv_rows == 0){
		largest_row = public.mask_conv_rows - 1;
		largest_col = largest_col - 1;
	}

	largest_row = largest_row + 1;																	
	largest_col = largest_col + 1;																	
	offset_row = largest_row - public.in_mod_rows - (public.sSize - public.tSize);
	offset_col = largest_col - public.in_mod_cols - (public.sSize - public.tSize);
	pointer = private_data.point_no*public.frames+public.frame_no;
	private_data.d_tRowLoc[pointer] = private_data.d_Row[private_data.point_no] + offset_row;
	private_data.d_tColLoc[pointer] = private_data.d_Col[private_data.point_no] + offset_col;

}

if(public.frame_no != 0 && (public.frame_no)%10 == 0){

	loc_pointer = private_data.point_no*public.frames+public.frame_no;
	private_data.d_Row[private_data.point_no] = private_data.d_tRowLoc[loc_pointer];
	private_data.d_Col[private_data.point_no] = private_data.d_tColLoc[loc_pointer];

	d_in = &private_data.d_T[private_data.in_pointer];
	for(col=0; col<public.in_mod_cols; col++){
		for(row=0; row<public.in_mod_rows; row++){

		ori_row = private_data.d_Row[private_data.point_no] - 25 + row - 1;
		ori_col = private_data.d_Col[private_data.point_no] - 25 + col - 1;
		ori_pointer = ori_col*public.frame_rows+ori_row;

		d_in[col*public.in_mod_rows+row] = public.alpha*d_in[col*public.in_mod_rows+row] + (1.00-public.alpha)*public.d_frame[ori_pointer];

		}
	}

}

}

__global__ void kernel_launcher(public_struct* d_public, private_struct* d_private, int point_idx){
	private_struct private_data = d_private[point_idx];
	public_struct public_data = d_public[0];

	kernel_cuda(public_data, private_data);

	d_private[point_idx] = private_data;
}

void write_data(	char* filename,
			int frameNo,
			int frames_processed,
			int endoPoints,
			int* input_a,
			int* input_b,
			int epiPoints,
			int* input_2a,
			int* input_2b){

	FILE* fid;
	int i,j;
	char c;

	fid = fopen(filename, "w+");
	if( fid == NULL ){
		printf( "The file was not opened for writing\n" );
		return;
	}

      fprintf(fid, "Total AVI Frames: %d\n", frameNo);	
      fprintf(fid, "Frames Processed: %d\n", frames_processed);	
      fprintf(fid, "endoPoints: %d\n", endoPoints);
      fprintf(fid, "epiPoints: %d", epiPoints);
	for(j=0; j<frames_processed;j++)
	  {
	    fprintf(fid, "\n---Frame %d---",j);
	    fprintf(fid, "\n--endo--\n",j);
	    for(i=0; i<endoPoints; i++){
	      fprintf(fid, "%d\t", input_a[j+i*frameNo]);
	    }
	    fprintf(fid, "\n");
	    for(i=0; i<endoPoints; i++){

	      fprintf(fid, "%d\t", input_b[j+i*frameNo]);
	    }
	    fprintf(fid, "\n--epi--\n",j);
	    for(i=0; i<epiPoints; i++){

	      fprintf(fid, "%d\t", input_2a[j+i*frameNo]);
	    }
	    fprintf(fid, "\n");
	    for(i=0; i<epiPoints; i++){

	      fprintf(fid, "%d\t", input_2b[j+i*frameNo]);
	    }
	  }

	fclose(fid);

}

