void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col) 
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1 = 1.f / Rx;
    FLOAT Ry_1 = 1.f / Ry;
    FLOAT Rz_1 = 1.f / Rz;
    FLOAT Cap_1 = step / Cap;

    // Allocate GPU memory
    int array_size = row * col;
    FLOAT *gpu_temp, *gpu_power, *gpu_result;
    cudaMalloc(&gpu_temp, array_size * sizeof(FLOAT));
    cudaMalloc(&gpu_power, array_size * sizeof(FLOAT));
    cudaMalloc(&gpu_result, array_size * sizeof(FLOAT));

    // Copy data to GPU
    cudaMemcpy(gpu_temp, temp, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);
    cudaMemcpy(gpu_power, power, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);

    // Setup kernel dimensions
    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C, 
              (row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R);

    // Iteration loop
    FLOAT *r = gpu_result;
    FLOAT *t = gpu_temp;

    for (int i = 0; i < num_iterations; i++) {
        single_iteration_kernel<<<grid, block>>>(r, t, gpu_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);

        // Swap pointers
        FLOAT *tmp = t;
        t = r;
        r = tmp;
    }

    // Copy result back to host (t points to final temperature data)
    cudaMemcpy(result, t, array_size * sizeof(FLOAT), cudaMemcpyDeviceToHost);

    // Cleanup GPU memory
    cudaFree(gpu_temp);
    cudaFree(gpu_power);
    cudaFree(gpu_result);
}

