    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    float *d_pIn, *d_tIn, *d_tOut, *d_tSwap;
