#include <cuda.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#include "./../main.h"
#include "./../util/timer/timer.h"

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

__global__ void kernel_cuda(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    int l = blockIdx.x;

    if (l >= dim.number_boxes) return;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                fp r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA[i].x - rB[j].x;
                d.y = rA[i].y - rB[j].y;
                d.z = rA[i].z - rB[j].z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA[i].v += qB[j] * vij;
                fA[i].x += qB[j] * fxij;
                fA[i].y += qB[j] * fyij;
                fA[i].z += qB[j] * fzij;
            }
        }
    }
}

void kernel_gpu_cuda_wrapper(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    long long time0;
    time0 = get_time();

    long long time1;
    long long time2;
    long long time3;
    long long time4;

    fp alpha;
    fp a2;

    time1 = get_time();

    setdevice();

    time2 = get_time();

    alpha = par.alpha;
    a2 = 2.0 * alpha * alpha;

    time3 = get_time();

    FOUR_VECTOR* rv_gpu;
    fp* qv_gpu;
    FOUR_VECTOR* fv_gpu;
    box_str* box_gpu;
    par_str par_gpu;
    dim_str dim_gpu;

    cudaMalloc(&rv_gpu, dim.space_mem);
    cudaMalloc(&qv_gpu, dim.space_mem2);
    cudaMalloc(&fv_gpu, dim.space_mem);
    cudaMalloc(&box_gpu, dim.box_mem);

    cudaMemcpy(rv_gpu, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(qv_gpu, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(fv_gpu, fv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(box_gpu, box, dim.box_mem, cudaMemcpyHostToDevice);

    par_gpu = par;
    dim_gpu = dim;

    kernel_cuda<<<dim.number_boxes, NUMBER_THREADS>>>(par_gpu, dim_gpu, box_gpu, rv_gpu, qv_gpu, fv_gpu);

    cudaMemcpy(fv, fv_gpu, dim.space_mem, cudaMemcpyDeviceToHost);

    cudaFree(rv_gpu);
    cudaFree(qv_gpu);
    cudaFree(fv_gpu);
    cudaFree(box_gpu);

    time4 = get_time();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");

    printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time4-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0)/1000000);
}

