#include "./../main.h"

#include "./../util/timer/timer.h"

#include "device.h"

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__global__ void kernel_gpu_cuda_kernel(
	par_str par,
	dim_str dim,
	box_str* box,
	FOUR_VECTOR* rv,
	fp* qv,
	FOUR_VECTOR* fv,
	fp alpha,
	fp a2)
{
	int l = blockIdx.x * blockDim.x + threadIdx.x;

	if (l >= dim.number_boxes) return;

	int i, j, k;
	long first_i;
	FOUR_VECTOR* rA;
	FOUR_VECTOR* fA;

	int pointer;
	long first_j;
	FOUR_VECTOR* rB;
	fp* qB;

	fp r2;
	fp u2;
	fp fs;
	fp vij;
	fp fxij, fyij, fzij;
	THREE_VECTOR d;

	first_i = box[l].offset;
	rA = &rv[first_i];
	fA = &fv[first_i];

	for (k = 0; k < (1 + box[l].nn); k++) {
		if (k == 0) {
			pointer = l;
		} else {
			pointer = box[l].nei[k - 1].number;
		}

		first_j = box[pointer].offset;
		rB = &rv[first_j];
		qB = &qv[first_j];

		for (i = 0; i < NUMBER_PAR_PER_BOX; i++) {
			for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
				r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
				u2 = a2 * r2;
				vij = exp(-u2);
				fs = 2.0 * vij;
				d.x = rA[i].x - rB[j].x;
				d.y = rA[i].y - rB[j].y;
				d.z = rA[i].z - rB[j].z;
				fxij = fs * d.x;
				fyij = fs * d.y;
				fzij = fs * d.z;

				fA[i].v += qB[j] * vij;
				fA[i].x += qB[j] * fxij;
				fA[i].y += qB[j] * fyij;
				fA[i].z += qB[j] * fzij;
			}
		}
	}
}

void kernel_gpu_cuda_wrapper(
	par_str par,
	dim_str dim,
	box_str* box_cpu,
	FOUR_VECTOR* rv_cpu,
	fp* qv_cpu,
	FOUR_VECTOR* fv_cpu)
{
	long long time0;
	time0 = get_time();

	long long time1;
	long long time2;
	long long time3;
	long long time4;

	fp alpha;
	fp a2;

	time1 = get_time();

	setdevice();

	time2 = get_time();

	alpha = par.alpha;
	a2 = 2.0 * alpha * alpha;

	time3 = get_time();

	box_str* box_gpu;
	FOUR_VECTOR* rv_gpu;
	fp* qv_gpu;
	FOUR_VECTOR* fv_gpu;

	cudaMalloc(&box_gpu, dim.box_mem);
	cudaMalloc(&rv_gpu, dim.space_mem);
	cudaMalloc(&qv_gpu, dim.space_mem2);
	cudaMalloc(&fv_gpu, dim.space_mem);

	cudaMemcpy(box_gpu, box_cpu, dim.box_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(rv_gpu, rv_cpu, dim.space_mem, cudaMemcpyHostToDevice);
	cudaMemcpy(qv_gpu, qv_cpu, dim.space_mem2, cudaMemcpyHostToDevice);
	cudaMemcpy(fv_gpu, fv_cpu, dim.space_mem, cudaMemcpyHostToDevice);

	int threads_per_block = NUMBER_THREADS;
	int num_blocks = (dim.number_boxes + threads_per_block - 1) / threads_per_block;

	kernel_gpu_cuda_kernel<<<num_blocks, threads_per_block>>>(
		par, dim, box_gpu, rv_gpu, qv_gpu, fv_gpu, alpha, a2);

	checkCUDAError("kernel launch");

	cudaMemcpy(fv_cpu, fv_gpu, dim.space_mem, cudaMemcpyDeviceToHost);

	cudaFree(box_gpu);
	cudaFree(rv_gpu);
	cudaFree(qv_gpu);
	cudaFree(fv_gpu);

	time4 = get_time();

	printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
	printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n",
		(float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n",
		(float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n",
		(float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time4 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n",
		(float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time4 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time4 - time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

