				box_cpu[nh].z = i;
				box_cpu[nh].number = nh;
				box_cpu[nh].offset = nh * NUMBER_PAR_PER_BOX;

				box_cpu[nh].nn = 0;

				for (l = -1; l < 2; l++) {
					for (m = -1; m < 2; m++) {
