__global__ void lud_inter_row_kernel(float *a, int size, int offset, int chunks_in_inter_row)
{
    int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k, i_global, j_global, i_here, j_here;
    float sum;           
    float temp[BS*BS];

    for (i = 0; i < BS; i++) {
        for (j =0; j < BS; j++){
            temp[i*BS + j] = a[size*(i + offset) + offset + j ];
        }
    }
    i_global = offset;
    j_global = offset;

    j_global += BS * (chunk_idx+1);
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            sum = 0.f;
            for (k=0; k < i; k++) {
