				 int* queryAddrs,
				 int* queryLengths,
				 PixelOfNode* nodeTexture,
				 PixelOfChildren* childrenTexture,
				 int numQueries,
				 int match_length,
				 int rc)
{
   int blocksize = 256;
   dim3 dimBlock(blocksize, 1, 1);
   dim3 dimGrid((numQueries + blocksize - 1) / blocksize, 1, 1);

   if (rc == REVERSE)
