#define OPEN 10000

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

__global__ void compute_distances(float *z, float *latitudes, float *longitudes, 
                                   float target_lat, float target_long, int rec_count) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        float tmp_lat = latitudes[i];
        float tmp_long = longitudes[i];
        z[i] = sqrt((tmp_lat - target_lat) * (tmp_lat - target_lat) + 
                    (tmp_long - target_long) * (tmp_long - target_long));
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE   *flist,*fp;
    int    i=0,j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], *rec_iter,*rec_iter2, dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long, tmp_lat=0, tmp_long=0;

