    for(int i = 0; i < BLOCK_SIZE; ++i) {
        for(int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols*(b_index_y*BLOCK_SIZE + i + 1) + b_index_x*BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1)*(BLOCK_SIZE + 1) + j + 1];
        }
    }
}

// CUDA kernel for processing blocks (bottom-right phase)
__global__ void nw_block_kernel_phase2(int *input_itemsets, int *referrence,
    int max_rows, int max_cols, int penalty, int blk, int max_blk) {

    int b_index_x = blk - 1 + blockIdx.x;
    int b_index_y = max_blk + blk - 2 - b_index_x;

    if(b_index_x >= max_blk || b_index_y < max_blk) return;

    // Local arrays for block computation
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference data
    for(int i = 0; i < BLOCK_SIZE; ++i) {
        for(int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i*BLOCK_SIZE + j] = referrence[max_cols*(b_index_y*BLOCK_SIZE + i + 1) + b_index_x*BLOCK_SIZE + j + 1];
        }
    }

    // Load input data
    for(int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for(int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i*(BLOCK_SIZE + 1) + j] = input_itemsets[max_cols*(b_index_y*BLOCK_SIZE + i) + b_index_x*BLOCK_SIZE + j];
        }
    }

    // Compute block values
    for(int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for(int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i*(BLOCK_SIZE + 1) + j] = maximum_device(
                input_itemsets_l[(i - 1)*(BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1)*BLOCK_SIZE + j - 1],
                input_itemsets_l[i*(BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1)*(BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    // Write results back
    for(int i = 0; i < BLOCK_SIZE; ++i) {
        for(int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols*(b_index_y*BLOCK_SIZE + i + 1) + b_index_x*BLOCK_SIZE + j + 1] = input_itemsets_l[(i + 1)*(BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int *d_input_itemsets, *d_referrence;
    size_t size = max_rows * max_cols * sizeof(int);

    // Allocate device memory
    cudaMalloc(&d_input_itemsets, size);
    cudaMalloc(&d_referrence, size);

    // Copy data to device
    cudaMemcpy(d_input_itemsets, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, size, cudaMemcpyHostToDevice);

    int max_blk = (max_cols - 1) / BLOCK_SIZE;

    // Phase 1: Top-left matrix
    printf("Processing top-left matrix\n");
    for(int blk = 1; blk <= max_blk; blk++) {
        nw_block_kernel_phase1<<<blk, 1>>>(d_input_itemsets, d_referrence,
            max_rows, max_cols, penalty, blk);
        cudaDeviceSynchronize();
    }

    // Phase 2: Bottom-right matrix
    printf("Processing bottom-right matrix\n");
    for(int blk = 2; blk <= max_blk; blk++) {
        int num_blocks = max_blk - blk + 1;
        nw_block_kernel_phase2<<<num_blocks, 1>>>(d_input_itemsets, d_referrence,
            max_rows, max_cols, penalty, blk, max_blk);
        cudaDeviceSynchronize();
    }

    // Copy results back
    cudaMemcpy(input_itemsets, d_input_itemsets, size, cudaMemcpyDeviceToHost);

    // Free device memory
    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

