__global__ void speedy_init_kernel(Point* p, int dim, long k1, long k2) {
  for( int k = k1 + threadIdx.x; k < k2; k += cuda_threads ) {
    float distance = dist(p[k],p[0],dim);
    p[k].cost = distance * p[k].weight;
    p[k].assign=0;
  }
}

__global__ void speedy_update_kernel(Point* p, int dim, long k1, long k2, int i) {
  for( int k = k1 + threadIdx.x; k < k2; k += cuda_threads ) {
    float distance = dist(p[i],p[k],dim);
    if( distance*p[k].weight < p[k].cost ) {
      p[k].cost = distance * p[k].weight;
      p[k].assign=i;
